def ensure_db():
    os.makedirs(DB_DIR, exist_ok=True)
    if not os.path.exists(USERS_FILE):
        sample_users = {
            "usuarios": [
                {
                    "id": "u-admin",
                    "nome": "Administrador",
                    "email": "admin@escola.com",
                    "senha": "Admin@123",
                    "tipo": "admin",
                    "matricula": "ADM001",
                    "aceitou_termos": True
                }
            ]
        }
        save_json(USERS_FILE, sample_users)
    files_to_create = [
        (TURMAS_FILE, {"turmas": []}),
        (ATIVIDADES_FILE, {"atividades": []}),
        (RESPOSTAS_FILE, {"respostas": []}),
        (NOTAS_FILE, {"notas": []}),
        (FREQUENCIA_FILE, {"frequencia": []}),
        (PROVAS_FILE, {"provas": []}),
        (ARQUIVOS_FILE, {"arquivos": []}),
        (CALCULOS_IA_FILE, {"calculos": []})
    ]
    for path, default in files_to_create:
        if not os.path.exists(path):
            save_json(path, default)

def load_json(path: str):
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {}

def save_json(path: str, data):
    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=2, ensure_ascii=False)

def gen_id(prefix: str):
    return f"{prefix}-{uuid.uuid4().hex[:8]}"

def gerar_matricula(tipo: str):
    numero = random.randint(1000, 9999)
    if tipo == "admin":
        return f"ADM{numero}"
    elif tipo == "professor":
        return f"PROF{numero}"
    else:
        return f"ALU{numero}"

def find_user_by_email(email: str):
    return next((u for u in load_json(USERS_FILE).get("usuarios", []) if u.get("email")==email), None)

def find_user_by_id(uid: str):
    return next((u for u in load_json(USERS_FILE).get("usuarios", []) if u.get("id")==uid), None)

def get_user_by_credentials(email: str, senha: str):
    return next((u for u in load_json(USERS_FILE).get("usuarios", []) if u.get("email")==email and u.get("senha")==senha), None)

def ensure_accepts_terms(user_data: dict) -> bool:
    return user_data.get("aceitou_termos", False)

# Arquivos (múltiplos anexos suportados)
def save_file_to_db(nome_arquivo: str, conteudo_base64: str, atividade_id: str = None, resposta_id: str = None, usuario_id: str = None):
    data = load_json(ARQUIVOS_FILE)
    arquivos = data.get("arquivos", [])
    novo = {
        "id": gen_id("arq"),
        "nome_arquivo": nome_arquivo,
        "conteudo_base64": conteudo_base64,
        "data_upload": datetime.now().isoformat(),
        "atividade_id": atividade_id,
        "resposta_id": resposta_id,
        "usuario_id": usuario_id
    }
    arquivos.append(novo)
    save_json(ARQUIVOS_FILE, {"arquivos": arquivos})
    return novo["id"]

def get_files_by_atividade(atividade_id: str):
    return [a for a in load_json(ARQUIVOS_FILE).get("arquivos", []) if a.get("atividade_id")==atividade_id]

def get_files_by_resposta(resposta_id: str):
    return [a for a in load_json(ARQUIVOS_FILE).get("arquivos", []) if a.get("resposta_id")==resposta_id]

def get_prova_aluno(prova_tipo: str, aluno_id: str):
    provas = load_json(PROVAS_FILE).get("provas", [])
    return next((p for p in provas if p.get("tipo")==prova_tipo and p.get("aluno_id")==aluno_id), None)


def download_file(arquivo_id: str, destino: str = None):
    data = load_json(ARQUIVOS_FILE)
    arqs = data.get("arquivos", [])
    for a in arqs:
        if a.get("id")==arquivo_id:
            if not destino:
                destino = filedialog.asksaveasfilename(initialfile=a.get("nome_arquivo"), title="Salvar arquivo como")
            if destino:
                conteudo = base64.b64decode(a.get("conteudo_base64",""))
                with open(destino, "wb") as f:
                    f.write(conteudo)
                return True
    return False

# Componentes
class PasswordEntry(ttk.Frame):
    def __init__(self, parent, width=30, **kwargs):
        super().__init__(parent)
        self.show_password = False
        entry_frame = ttk.Frame(self)
        entry_frame.pack(fill="x")
        self.entry = ttk.Entry(entry_frame, width=width, show="•", **kwargs)
        self.entry.pack(side="left", fill="x", expand=True)
        self.toggle_btn = ttk.Button(entry_frame, text="👁️", width=3, command=self.toggle_password)
        self.toggle_btn.pack(side="right", padx=(4,0))
    def toggle_password(self):
        self.show_password = not self.show_password
        if self.show_password:
            self.entry.config(show="")
            self.toggle_btn.config(text="🔒")
        else:
            self.entry.config(show="•")
            self.toggle_btn.config(text="👁️")
    def get(self):
        return self.entry.get()
    def delete(self, first, last=None):
        return self.entry.delete(first, last)
    def insert(self, index, string):
        return self.entry.insert(index, string)

class App(tk.Tk):
    def __init__(self):
        super().__init__()
        self.title("SystemAdsers - Plataforma Acadêmica")
        self.geometry("1100x700")
        self.minsize(1000,640)
        self.configure(bg=PRIMARY_BG)
        style = ttk.Style(self)
        try:
            style.theme_use("clam")
        except Exception:
            pass
        style.configure("Sidebar.TFrame", background=SIDEBAR_BG)
        style.configure("Header.TFrame", background=HEADER_BG)
        style.configure("Card.TFrame", background=CARD_BG, relief="raised")
        style.configure("TLabel", background=PRIMARY_BG)
        style.configure("Title.TLabel", font=("Segoe UI", 14, "bold"))
        style.configure("Subtitle.TLabel", font=("Segoe UI", 10))
        style.configure("Sidebar.TLabel", background=SIDEBAR_BG, foreground=SIDEBAR_FG, font=("Segoe UI", 12, "bold"))
        style.configure("Big.TButton", font=("Segoe UI", 10, "bold"), padding=6)
        style.configure("Primary.TButton", background=ACCENT_COLOR, foreground="white")
        style.configure("Success.TButton", background=SUCCESS_COLOR, foreground="white")
        style.configure("Warning.TButton", background=WARNING_COLOR, foreground="white")
        style.configure("Danger.TButton", background=DANGER_COLOR, foreground="white")

        self.current_user: Optional[dict] = None

        self.header_frame = ttk.Frame(self, style="Header.TFrame", height=60)
        self.header_frame.pack(side="top", fill="x")
        self.sidebar_frame = ttk.Frame(self, style="Sidebar.TFrame", width=220)
        self.sidebar_frame.pack(side="left", fill="y")
        self.container = ttk.Frame(self, padding=12)
        self.container.pack(side="left", fill="both", expand=True)

        self._build_header()
        self._build_sidebar()
        self.screens = {}
        self.show_screen(TermoUsoScreen)

    def _build_header(self):
        title = ttk.Label(self.header_frame, text="🏫 SystemAdsers - Plataforma Acadêmica", style="Title.TLabel", foreground="white", background=HEADER_BG)
        title.pack(side="left", padx=12, pady=10)
        self.header_info = ttk.Label(self.header_frame, text="", style="Subtitle.TLabel", foreground="white", background=HEADER_BG)
        self.header_info.pack(side="right", padx=12)

    def _build_sidebar(self):
        for w in self.sidebar_frame.winfo_children():
            w.destroy()

        # Cria layout base
        top_frame = ttk.Frame(self.sidebar_frame, style="Sidebar.TFrame")
        top_frame.pack(side="top", fill="x", pady=(20, 10))

        middle_frame = ttk.Frame(self.sidebar_frame, style="Sidebar.TFrame")
        middle_frame.pack(side="top", fill="both", expand=True)

        bottom_frame = ttk.Frame(self.sidebar_frame, style="Sidebar.TFrame")
        bottom_frame.pack(side="bottom", fill="x", pady=(10, 20))

        # 🔹 Mantém compatibilidade com outras funções
        self.sidebar_buttons_frame = middle_frame

        # --- Cabeçalho ---
        logo_text = ttk.Label(
            top_frame,
            text="🏫 Sistema Adsers",
            style="Sidebar.TLabel",
            anchor="center",
            justify="center",
            wraplength=160
        )
        logo_text.pack(pady=(0, 10))

        # --- Botões principais ---
        btn_login = ttk.Button(
            self.sidebar_buttons_frame,
            text="🔐 Login",
            command=lambda: self.show_screen(LoginScreen),
            style="Primary.TButton"
        )
        btn_login.pack(fill="x", padx=20, pady=6)

        btn_cadastro = ttk.Button(
            self.sidebar_buttons_frame,
            text="📝 Cadastrar",
            command=lambda: self.show_screen(SignUpScreen),
            style="Success.TButton"
        )
        btn_cadastro.pack(fill="x", padx=20, pady=6)
        # --- Cabeçalho ---
        # Logo em base64 (ADICIONE A STRING COMPLETA DO logo_b64 AQUI)
        logo_b64 = """"""

        try:
            logo_data = base64.b64decode(logo_b64)
            self.original_logo = Image.open(BytesIO(logo_data))
        except Exception as e:
            print("⚠️ Erro ao carregar logo:", e)
            return

        # Cria label para exibir a logo
        logo_label = ttk.Label(bottom_frame)
        logo_label.pack(anchor="center", pady=(0, 5))

        # Função para redimensionar dinamicamente
        def resize_logo(event=None):
            try:
                width = max(80, min(160, int(self.sidebar_frame.winfo_width() * 0.6)))
                resized = self.original_logo.resize((width, width), Image.LANCZOS)
                self.logo_img = ImageTk.PhotoImage(resized)
                logo_label.config(image=self.logo_img)
            except Exception as e:
                print("Erro ao redimensionar logo:", e)

        # Exibe imediatamente e ao redimensionar
        resize_logo()
        self.sidebar_frame.bind("<Configure>", resize_logo)

        # --- Texto abaixo da logo ---
        version_label = ttk.Label(
            bottom_frame,
            text="© 2025 Sistema Adsers v1.0",
            style="Sidebar.TLabel",
            font=("Segoe UI", 8),
            anchor="center",
            justify="center"
        )
        version_label.pack(anchor="center", pady=(4, 0))

        def resize_logo(event=None):
            width = max(80, min(160, int(self.sidebar_frame.winfo_width() * 0.6)))
            resized = self.original_logo.resize((width, width), Image.LANCZOS)
            self.logo_img = ImageTk.PhotoImage(resized)
            logo_label.config(image=self.logo_img)

        resize_logo()
        self.sidebar_frame.bind("<Configure>", resize_logo)

        version_label.pack(anchor="center", pady=(4, 0))
    def populate_sidebar_for_user(self):
        for w in self.sidebar_buttons_frame.winfo_children():
            w.destroy()
        usr = self.current_user
        if not usr:
            self._build_sidebar()
            return
        
        home_btn = ttk.Button(self.sidebar_buttons_frame, text="🏠 Dashboard", command=lambda: self.show_dashboard(), style="Primary.TButton")
        home_btn.pack(fill="x", padx=12, pady=4)
        profile_btn = ttk.Button(self.sidebar_buttons_frame, text="👤 Meu Perfil", command=lambda: self.show_screen(ProfileScreen), style="Primary.TButton")
        profile_btn.pack(fill="x", padx=12, pady=4)
        
        if usr.get("tipo") == "admin":
            ttk.Button(self.sidebar_buttons_frame, text="👥 Gerenciar Usuários", command=lambda: self.show_screen(UserManagementScreen), style="Warning.TButton").pack(fill="x", padx=12, pady=4)
            ttk.Button(self.sidebar_buttons_frame, text="📚 Gerenciar Turmas", command=lambda: self.show_screen(TurmaManagementScreen), style="Warning.TButton").pack(fill="x", padx=12, pady=4)
            ttk.Button(self.sidebar_buttons_frame, text="📊 Relatórios", command=lambda: self.show_screen(ReportsScreen), style="Primary.TButton").pack(fill="x", padx=12, pady=4)
            ttk.Button(self.sidebar_buttons_frame, text="📈 Desempenho de Aluno", command=lambda: self.show_screen(StudentPerformanceScreen), style="Primary.TButton").pack(fill="x", padx=12, pady=4)
            
        if usr.get("tipo") == "professor":
            ttk.Button(self.sidebar_buttons_frame, text="➕ Criar Atividade", command=lambda: self.show_screen(CreateActivityScreen), style="Success.TButton").pack(fill="x", padx=12, pady=4)
            ttk.Button(self.sidebar_buttons_frame, text="📚 Gerenciar Turmas", command=lambda: self.show_screen(TurmaManagementScreen), style="Primary.TButton").pack(fill="x", padx=12, pady=4)
            ttk.Button(self.sidebar_buttons_frame, text="📊 Relatórios", command=lambda: self.show_screen(ReportsScreen), style="Primary.TButton").pack(fill="x", padx=12, pady=4)
            ttk.Button(self.sidebar_buttons_frame, text="📈 Desempenho de Aluno", command=lambda: self.show_screen(StudentPerformanceScreen), style="Primary.TButton").pack(fill="x", padx=12, pady=4)
            ttk.Button(self.sidebar_buttons_frame, text="📤 Atividades Postadas", command=lambda: self.show_screen(ProfessorActivitiesScreen), style="Primary.TButton").pack(fill="x", padx=12, pady=4)
            ttk.Button(self.sidebar_buttons_frame, text="💯 Corrigir Provas", command=lambda: self.show_screen(ProfessorExamsScreen), style="Primary.TButton").pack(fill="x", padx=12, pady=4)
            
        if usr.get("tipo") == "aluno":
            ttk.Button(self.sidebar_buttons_frame, text="📝 Atividades", command=lambda: self.show_screen(StudentActivitiesScreen), style="Primary.TButton").pack(fill="x", padx=12, pady=4)
            ttk.Button(self.sidebar_buttons_frame, text="💯 Notas de Prova", command=lambda: self.show_screen(StudentExamsScreen), style="Primary.TButton").pack(fill="x", padx=12, pady=4)
            ttk.Button(self.sidebar_buttons_frame, text="📅 Frequência", command=lambda: self.show_screen(FrequencyScreen), style="Primary.TButton").pack(fill="x", padx=12, pady=4)
            ttk.Button(self.sidebar_buttons_frame, text="📈 Meu Desempenho", command=lambda: self.show_screen(StudentPerformanceScreen), style="Primary.TButton").pack(fill="x", padx=12, pady=4)
            
        ttk.Button(self.sidebar_buttons_frame, text="🚪 Sair", command=self.logout, style="Danger.TButton").pack(side="bottom", fill="x", padx=12, pady=12)

    def logout(self):
        self.current_user = None
        messagebox.showinfo("Logout", "Você foi desconectado.")
        self.header_info.config(text="")
        self.populate_sidebar_for_user()
        self.show_screen(LoginScreen)

    def set_current_user(self, user: dict):
        self.current_user = user
        self.header_info.config(text=f"{user.get('nome')} — {user.get('tipo').capitalize()} — Matrícula: {user.get('matricula', 'N/A')}")
        self.populate_sidebar_for_user()

    def show_dashboard(self):
        if not self.current_user:
            self.show_screen(LoginScreen)
            return
        tipo = self.current_user.get("tipo")
        if tipo == "admin":
            self.show_screen(AdminDashboard)
        elif tipo == "professor":
            self.show_screen(ProfessorDashboard)
        elif tipo == "aluno":
            self.show_screen(StudentDashboard)
        else:
            self.show_screen(LoginScreen)

    def show_screen(self, screen_class):
        for w in self.container.winfo_children():
            w.destroy()
        screen = screen_class(parent=self.container, app=self)
        screen.pack(fill="both", expand=True)
        self.screens[screen_class.__name__] = screen

# Screens (termo, signup, login, profile) - mantidos
class TermoUsoScreen(ttk.Frame):
    def __init__(self, parent, app: App):
        super().__init__(parent)
        self.app = app
        self.configure(style="Card.TFrame", padding=18)
        lbl_title = ttk.Label(self, text="📋 Termo de Uso - Armazenamento Local (LGPD Simplificado)", style="Title.TLabel")
        lbl_title.pack(anchor="w")
        termo_text = (
            "Este sistema armazena localmente informações pessoais (nome, e-mail, matrícula, notas e frequência) "
            "para fins de controle acadêmico. Os dados NÃO são enviados para serviços externos.\n\n"
            "Ao continuar você concorda com o armazenamento local dos seus dados para uso acadêmico."
        )
        txt = tk.Text(self, height=10, wrap="word", padx=8, pady=8)
        txt.insert("1.0", termo_text)
        txt.configure(state="disabled", bg="#FFFFFF")
        txt.pack(fill="x", pady=8)
        self.var_aceito = tk.BooleanVar(value=False)
        chk = ttk.Checkbutton(self, text="Li e aceito os termos de uso", variable=self.var_aceito)
        chk.pack(anchor="w", pady=6)
        btn = ttk.Button(self, text="✅ Continuar", style="Success.TButton", command=self.continuar)
        btn.pack(pady=8, anchor="e")
    def continuar(self):
        if not self.var_aceito.get():
            messagebox.showwarning("Termos", "Você precisa aceitar os termos para continuar.")
            return
        self.app.show_screen(LoginScreen)

class SignUpScreen(ttk.Frame):
    def __init__(self, parent, app: App):
        super().__init__(parent, padding=16)
        self.app = app
        title = ttk.Label(self, text="📝 Cadastro de Novo Usuário", style="Title.TLabel")
        title.pack(anchor="w", pady=(6,12))
        form_frame = ttk.Frame(self)
        form_frame.pack(fill="both", expand=True, padx=10, pady=8)
        ttk.Label(form_frame, text="Nome completo:").grid(row=0, column=0, sticky="w", pady=4)
        self.nome_entry = ttk.Entry(form_frame, width=40)
        self.nome_entry.grid(row=0, column=1, sticky="w", padx=6, pady=4)
        ttk.Label(form_frame, text="E-mail:").grid(row=1, column=0, sticky="w", pady=4)
        self.email_entry = ttk.Entry(form_frame, width=40)
        self.email_entry.grid(row=1, column=1, sticky="w", padx=6, pady=4)
        ttk.Label(form_frame, text="Senha:").grid(row=2, column=0, sticky="w", pady=4)
        self.senha_entry = PasswordEntry(form_frame, width=40)
        self.senha_entry.grid(row=2, column=1, sticky="w", padx=6, pady=4)
        ttk.Label(form_frame, text="Confirmar senha:").grid(row=3, column=0, sticky="w", pady=4)
        self.confirmar_senha_entry = PasswordEntry(form_frame, width=40)
        self.confirmar_senha_entry.grid(row=3, column=1, sticky="w", padx=6, pady=4)
        btn_frame = ttk.Frame(self)
        btn_frame.pack(fill="x", pady=12)
        ttk.Button(btn_frame, text="✅ Cadastrar", style="Success.TButton", command=self.cadastrar).pack(side="left", padx=6)
        ttk.Button(btn_frame, text="↩️ Voltar para Login", command=lambda: self.app.show_screen(LoginScreen), style="Primary.TButton").pack(side="left", padx=6)
    def validar_senha(self, senha):
        if len(senha) < 8:
            return False
        tem_maiuscula = any(c.isupper() for c in senha)
        if not tem_maiuscula:
            return False
        caracteres_especiais = set('@#$%&*!?+-_=^~|/')
        tem_especial = any(c in caracteres_especiais for c in senha)
        if not tem_especial:
            return False
        return True
    def cadastrar(self):
        nome = self.nome_entry.get().strip()
        email = self.email_entry.get().strip()
        senha = self.senha_entry.get().strip()
        confirmar_senha = self.confirmar_senha_entry.get().strip()
        if not nome or not email or not senha or not confirmar_senha:
            messagebox.showwarning("Campos obrigatórios", "Preencha todos os campos.")
            return
        if senha != confirmar_senha:
            messagebox.showerror("Senhas diferentes", "As senhas não coincidem.")
            return
        if not self.validar_senha(senha):
            messagebox.showwarning("Senha fraca", "A senha deve ter pelo menos 8 caracteres, 1 maiúscula e 1 caractere especial.")
            return
        if find_user_by_email(email):
            messagebox.showerror("Email existente", "Este email já está cadastrado.")
            return
        data = load_json(USERS_FILE)
        users = data.get("usuarios", [])
        matricula_gerada = gerar_matricula("aluno")
        new_user = {
            "id": gen_id("u"),
            "nome": nome,
            "email": email,
            "senha": senha,
            "tipo": "aluno",
            "matricula": matricula_gerada,
            "aceitou_termos": True
        }
        users.append(new_user)
        save_json(USERS_FILE, {"usuarios": users})
        messagebox.showinfo("Cadastro realizado", f"Cadastro realizado com sucesso!\nSua matrícula: {matricula_gerada}")
        self.app.show_screen(LoginScreen)

class LoginScreen(ttk.Frame):
    def __init__(self, parent, app: App):
        super().__init__(parent, padding=16)
        self.app = app
        title = ttk.Label(self, text="🔐 Acessar Plataforma", style="Title.TLabel")
        title.pack(anchor="w", pady=(6,12))
        ttk.Label(self, text="E-mail:").pack(anchor="w")
        self.email_entry = ttk.Entry(self, width=40)
        self.email_entry.pack(anchor="w", pady=4)
        ttk.Label(self, text="Senha:").pack(anchor="w")
        self.senha_entry = PasswordEntry(self, width=40)
        self.senha_entry.pack(anchor="w", pady=4)
        btn_frame = ttk.Frame(self)
        btn_frame.pack(fill="x", pady=12)
        ttk.Button(btn_frame, text="✅ Entrar", style="Success.TButton", command=self.login).pack(side="left", padx=6)
        ttk.Button(btn_frame, text="📝 Cadastrar", command=lambda: app.show_screen(SignUpScreen), style="Primary.TButton").pack(side="left", padx=6)
    def login(self):
        email = self.email_entry.get().strip()
        senha = self.senha_entry.get().strip()
        if not email or not senha:
            messagebox.showwarning("Entrada inválida", "Preencha e-mail e senha.")
            return
        user = get_user_by_credentials(email, senha)
        if not user:
            messagebox.showerror("Erro", "Credenciais inválidas.")
            return
        if not ensure_accepts_terms(user):
            messagebox.showwarning("Termos", "Usuário não aceitou os termos.")
            return
        self.app.set_current_user(user)
        messagebox.showinfo("Bem-vindo", f"Olá {user.get('nome')}!")
        self.app.show_dashboard()

class ProfileScreen(ttk.Frame):
    def __init__(self, parent, app: App):
        super().__init__(parent, padding=12)
        self.app = app
        user = self.app.current_user
        ttk.Label(self, text="👤 Meu Perfil", style="Title.TLabel").pack(anchor="w")
        frm = ttk.Frame(self)
        frm.pack(fill="x", pady=6)
        frm.columnconfigure(0, weight=0, minsize=120)
        frm.columnconfigure(1, weight=1, minsize=300)
        ttk.Label(frm, text="Nome:").grid(row=0, column=0, sticky="w", pady=8, padx=(0,10))
        self.nome_var = tk.StringVar(value=user.get("nome"))
        ttk.Entry(frm, textvariable=self.nome_var, width=50).grid(row=0, column=1, sticky="ew", pady=8)
        ttk.Label(frm, text="E-mail:").grid(row=1, column=0, sticky="w", pady=8, padx=(0,10))
        ttk.Label(frm, text=user.get("email")).grid(row=1, column=1, sticky="w", pady=8)
        ttk.Label(frm, text="Tipo:").grid(row=2, column=0, sticky="w", pady=8, padx=(0,10))
        ttk.Label(frm, text=user.get("tipo")).grid(row=2, column=1, sticky="w", pady=8)
        ttk.Label(frm, text="Matrícula:").grid(row=3, column=0, sticky="w", pady=8, padx=(0,10))
        ttk.Label(frm, text=user.get("matricula")).grid(row=3, column=1, sticky="w", pady=8)
        ttk.Label(frm, text="Senha (nova):").grid(row=4, column=0, sticky="w", pady=8, padx=(0,10))
        self.senha_entry = PasswordEntry(frm, width=30)
        self.senha_entry.grid(row=4, column=1, sticky="w", pady=8)
        ttk.Button(self, text="💾 Salvar Alterações", command=self.save, style="Success.TButton").pack(anchor="e", pady=8)
    def validar_senha(self, senha):
        if len(senha) < 8:
            return False
        tem_maiuscula = any(c.isupper() for c in senha)
        if not tem_maiuscula:
            return False
        caracteres_especiais = set('@#$%&*!?+-_=^~|/')
        tem_especial = any(c in caracteres_especiais for c in senha)
        if not tem_especial:
            return False
        return True
    def save(self):
        users = load_json(USERS_FILE).get("usuarios", [])
        uid = self.app.current_user.get("id")
        new_senha = self.senha_entry.get().strip()
        if new_senha:
            if not self.validar_senha(new_senha):
                messagebox.showwarning("Senha fraca", "A senha deve ter pelo menos 8 caracteres, 1 maiúscula e 1 caractere especial.")
                return
        for u in users:
            if u.get("id")==uid:
                u["nome"] = self.nome_var.get().strip() or u["nome"]
                if new_senha:
                    u["senha"] = new_senha
                break
        save_json(USERS_FILE, {"usuarios": users})
        messagebox.showinfo("Perfil", "Dados atualizados.")
        self.app.set_current_user(find_user_by_id(uid))

