# Turma Management - CORRIGIDO
class TurmaManagementScreen(ttk.Frame):
    def __init__(self, parent, app: App):
        super().__init__(parent, padding=12)
        self.app = app
        self.selected_turma = None
        
        ttk.Label(self, text="📚 Gerenciar Turmas", style="Title.TLabel").pack(anchor="w")
        
        toolbar = ttk.Frame(self)
        toolbar.pack(fill="x", pady=8)
        
        # Botões centralizados com texto
        btn_add = ttk.Button(toolbar, text="➕ Adicionar Turma", command=self.add_turma, style="Success.TButton")
        btn_add.pack(side="left", padx=6)
        
        btn_edit = ttk.Button(toolbar, text="✏️ Editar Turma", command=self.edit_selected_turma, style="Warning.TButton")
        btn_edit.pack(side="left", padx=6)
        
        btn_delete = ttk.Button(toolbar, text="🗑️ Excluir Turma", command=self.delete_selected_turma, style="Danger.TButton")
        btn_delete.pack(side="left", padx=6)
        
        btn_refresh = ttk.Button(toolbar, text="🔄 Atualizar", command=self.refresh, style="Primary.TButton")
        btn_refresh.pack(side="left", padx=6)
        
        tree_frame = ttk.Frame(self)
        tree_frame.pack(fill="both", expand=True)
        
        columns = ("nome", "disciplina", "professor", "alunos")
        self.tree = ttk.Treeview(tree_frame, columns=columns, show="headings")
        self.tree.heading("nome", text="Nome da Turma")
        self.tree.heading("disciplina", text="Disciplina")
        self.tree.heading("professor", text="Professor")
        self.tree.heading("alunos", text="Nº de Alunos")
        
        self.tree.column("nome", width=200)
        self.tree.column("disciplina", width=150)
        self.tree.column("professor", width=150)
        self.tree.column("alunos", width=100)
        
        scrollbar = ttk.Scrollbar(tree_frame, orient="vertical", command=self.tree.yview)
        self.tree.configure(yscrollcommand=scrollbar.set)
        self.tree.pack(side="left", fill="both", expand=True)
        scrollbar.pack(side="right", fill="y")
        
        self.tree.bind("<<TreeviewSelect>>", self.on_select)
        
        self.refresh()

    def on_select(self, event):
        selection = self.tree.selection()
        if selection:
            item = self.tree.item(selection[0])
            self.selected_turma = item["values"]

    def refresh(self):
        for item in self.tree.get_children():
            self.tree.delete(item)
        turmas = load_json(TURMAS_FILE).get("turmas", [])
        users = load_json(USERS_FILE).get("usuarios", [])
        
        for turma in turmas:
            current_user = self.app.current_user
            if current_user.get("tipo") == "professor" and turma.get("professor_id") != current_user.get("id"):
                continue
                
            professor_nome = "N/A"
            for user in users:
                if user.get("id") == turma.get("professor_id"):
                    professor_nome = user.get("nome")
                    break
            
            num_alunos = len(turma.get("alunos", []))
            self.tree.insert("", "end", values=(
                turma.get("nome"),
                turma.get("disciplina"),
                professor_nome,
                num_alunos
            ))

    def add_turma(self):
        AddTurmaDialog(self, self.app)

    def edit_selected_turma(self):
        if not self.selected_turma:
            messagebox.showwarning("Seleção", "Selecione uma turma para editar.")
            return
        
        turmas = load_json(TURMAS_FILE).get("turmas", [])
        selected_nome = self.selected_turma[0]
        
        for turma in turmas:
            if turma.get("nome") == selected_nome:
                EditTurmaDialog(self, self.app, turma)
                break

    def delete_selected_turma(self):
        if not self.selected_turma:
            messagebox.showwarning("Seleção", "Selecione uma turma para excluir.")
            return
            
        selected_nome = self.selected_turma[0]
        if messagebox.askyesno("Confirmar", f"Excluir turma {selected_nome}?"):
            turmas = load_json(TURMAS_FILE).get("turmas", [])
            turmas = [t for t in turmas if t.get("nome") != selected_nome]
            save_json(TURMAS_FILE, {"turmas": turmas})
            self.refresh()

class AddTurmaDialog(tk.Toplevel):
    def __init__(self, parent: TurmaManagementScreen, app: App):
        super().__init__(parent)
        self.parent = parent
        self.app = app
        self.title("➕ Adicionar Turma")
        self.geometry("500x400")
        self.resizable(False, False)
        self.transient(parent)
        self.grab_set()
        
        # Configurar grid para o dialog principal
        self.grid_rowconfigure(1, weight=1)
        self.grid_columnconfigure(0, weight=1)
        
        main_frame = ttk.Frame(self, padding=12)
        main_frame.pack(fill="both", expand=True)
        
        ttk.Label(main_frame, text="Nome da Turma:").pack(anchor="w", pady=4)
        self.nome_entry = ttk.Entry(main_frame, width=40)
        self.nome_entry.pack(fill="x", pady=4)
        
        ttk.Label(main_frame, text="Disciplina:").pack(anchor="w", pady=4)
        self.disciplina_entry = ttk.Entry(main_frame, width=40)
        self.disciplina_entry.pack(fill="x", pady=4)
        
        # Apenas admin pode atribuir professor
        if self.app.current_user.get("tipo") == "admin":
            ttk.Label(main_frame, text="Professor:").pack(anchor="w", pady=4)
            self.professor_var = tk.StringVar()
            self.professor_combo = ttk.Combobox(main_frame, textvariable=self.professor_var, state="readonly")
            
            users = load_json(USERS_FILE).get("usuarios", [])
            professores = [f"{u.get('nome')} ({u.get('email')})" for u in users if u.get("tipo") == "professor"]
            self.professor_combo["values"] = professores
            if professores:
                self.professor_combo.set(professores[0])
            self.professor_combo.pack(fill="x", pady=4)
        else:
            # Professor não pode alterar professor da turma
            self.professor_id = self.app.current_user.get("id")
        
        ttk.Label(main_frame, text="Alunos:").pack(anchor="w", pady=4)
        
        # CORREÇÃO: Frame para lista de alunos usando grid
        alunos_frame = ttk.Frame(main_frame)
        alunos_frame.pack(fill="both", expand=True, pady=4)
        alunos_frame.grid_rowconfigure(0, weight=1)
        alunos_frame.grid_columnconfigure(0, weight=1)
        
        # CORREÇÃO: Frame para listbox e scrollbar
        self.alunos_listbox_frame = ttk.Frame(alunos_frame)
        self.alunos_listbox_frame.grid(row=0, column=0, sticky="nsew")
        self.alunos_listbox_frame.grid_rowconfigure(0, weight=1)
        self.alunos_listbox_frame.grid_columnconfigure(0, weight=1)
        
        # CORREÇÃO: Listbox de alunos
        self.alunos_listbox = tk.Listbox(self.alunos_listbox_frame, selectmode="multiple", height=8)
        self.alunos_listbox.grid(row=0, column=0, sticky="nsew")
        
        # CORREÇÃO: Scrollbar
        scrollbar = ttk.Scrollbar(self.alunos_listbox_frame, orient="vertical", command=self.alunos_listbox.yview)
        scrollbar.grid(row=0, column=1, sticky="ns")
        self.alunos_listbox.configure(yscrollcommand=scrollbar.set)
        
        users = load_json(USERS_FILE).get("usuarios", [])
        alunos_users = [u for u in users if u.get("tipo") == "aluno"]
        self.alunos_data = []
        for aluno in alunos_users:
            display_text = f"{aluno.get('nome')} ({aluno.get('email')})"
            self.alunos_listbox.insert("end", display_text)
            self.alunos_data.append(aluno)
        
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill="x", pady=12)
        
        # Botões centralizados com texto
        btn_save = ttk.Button(btn_frame, text="✅ Salvar", style="Success.TButton", command=self.save)
        btn_save.pack(side="left", padx=6)
        
        btn_cancel = ttk.Button(btn_frame, text="❌ Cancelar", style="Danger.TButton", command=self.destroy)
        btn_cancel.pack(side="left", padx=6)

    def save(self):
        nome = self.nome_entry.get().strip()
        disciplina = self.disciplina_entry.get().strip()
        
        if not nome or not disciplina:
            messagebox.showwarning("Campos obrigatórios", "Preencha todos os campos.")
            return
        
        # Obter professor_id baseado no tipo de usuário
        if self.app.current_user.get("tipo") == "admin":
            professor_selecionado = self.professor_var.get()
            if not professor_selecionado:
                messagebox.showwarning("Campos obrigatórios", "Selecione um professor.")
                return
            
            professor_email = professor_selecionado.split("(")[-1].rstrip(")")
            users = load_json(USERS_FILE).get("usuarios", [])
            professor_id = None
            for user in users:
                if user.get("email") == professor_email:
                    professor_id = user.get("id")
                    break
            
            if not professor_id:
                messagebox.showerror("Erro", "Professor não encontrado.")
                return
        else:
            professor_id = self.professor_id
        
        alunos_selecionados_indices = self.alunos_listbox.curselection()
        alunos_ids = []
        for idx in alunos_selecionados_indices:
            alunos_ids.append(self.alunos_data[idx].get("id"))
        
        data = load_json(TURMAS_FILE)
        turmas = data.get("turmas", [])
        
        for turma in turmas:
            if turma.get("nome") == nome:
                messagebox.showerror("Turma existente", "Já existe uma turma com este nome.")
                return
        
        new_turma = {
            "id": gen_id("t"),
            "nome": nome,
            "disciplina": disciplina,
            "professor_id": professor_id,
            "alunos": alunos_ids
        }
        
        turmas.append(new_turma)
        save_json(TURMAS_FILE, {"turmas": turmas})
        messagebox.showinfo("Sucesso", f"Turma {nome} adicionada com sucesso!")
        self.parent.refresh()
        self.destroy()

